using System.ComponentModel;
using System.Text;
using System.Text.Json;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

// --- Build the IChatClient through MEAI ---
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Instantiate the tools ---
var researchTools = new ResearchTools();

// --- Create the agent with tools ---
var agent = new ChatClientAgent(
    chatClient,
    new ChatClientAgentOptions
    {
        Name = "ResearchAgent",
        Description = "An AI agent that researches topics by searching the web and taking notes, then summarizes findings.",
        ChatOptions = new ChatOptions
        {
            Temperature = 0f,
            MaxOutputTokens = 2048,
            Tools = [
                AIFunctionFactory.Create(researchTools.SearchWeb),
                AIFunctionFactory.Create(researchTools.SaveNote),
                AIFunctionFactory.Create(researchTools.GetNotes),
            ],
        },
    },
    instructions: """
        You are a research assistant. When given a topic:
        1. Use the SearchWeb tool multiple times with different queries to gather diverse information.
        2. Use the SaveNote tool to record key findings as you go — include the source query.
        3. After gathering enough information (at least 3 searches), use GetNotes to review everything.
        4. Produce a well-structured summary with sections, key points, and source references.
        Be thorough but concise.
        """);

// --- Run the agent ---
Console.WriteLine("Research Agent Starting...");
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();

if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\nResearching: {topic}\n");

using var cts = new CancellationTokenSource(TimeSpan.FromMinutes(3));
var session = await agent.CreateSessionAsync(cancellationToken: cts.Token);

var response = await agent.RunAsync(
    $"Research the following topic and provide a comprehensive summary: {topic}",
    session,
    cancellationToken: cts.Token);

Console.WriteLine("═══════════════════════════════════════");
Console.WriteLine("  RESEARCH SUMMARY");
Console.WriteLine("═══════════════════════════════════════");
Console.WriteLine(response.Text);
Console.WriteLine("═══════════════════════════════════════");
Console.WriteLine($"\nNotes taken: {researchTools.NoteCount}");
Console.WriteLine($"Searches performed: {researchTools.SearchCount}");

// --- Tool definitions ---

/// <summary>Tools for web search and note-taking used by the research agent.</summary>
sealed class ResearchTools
{
    private readonly List<string> _notes = [];
    private int _searchCount;

    public int NoteCount => _notes.Count;
    public int SearchCount => _searchCount;

    [Description("Searches the web for a given query and returns a summary of results. Use this to find information about a topic.")]
    public string SearchWeb([Description("The search query string")] string query)
    {
        Interlocked.Increment(ref _searchCount);
        Console.WriteLine($"  🔍 Searching: \"{query}\"");

        // Simulated web search results — in production, wire up Bing Search API or similar.
        var results = SimulateSearchResults(query);
        return JsonSerializer.Serialize(new { query, results }, new JsonSerializerOptions { WriteIndented = true });
    }

    [Description("Saves a research note for later reference. Use this to record key findings from searches.")]
    public string SaveNote(
        [Description("The note content to save")] string content,
        [Description("The source or context of this note")] string source)
    {
        var note = $"[Source: {source}] {content}";
        _notes.Add(note);
        Console.WriteLine($"  📝 Note saved ({_notes.Count}): {Truncate(content, 80)}");
        return $"Note #{_notes.Count} saved successfully.";
    }

    [Description("Retrieves all previously saved research notes.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes have been saved yet.";

        Console.WriteLine($"  📋 Reviewing {_notes.Count} notes");

        var sb = new StringBuilder();
        for (var i = 0; i < _notes.Count; i++)
            sb.AppendLine($"Note #{i + 1}: {_notes[i]}");

        return sb.ToString();
    }

    private static string Truncate(string text, int maxLength) =>
        text.Length <= maxLength ? text : string.Concat(text.AsSpan(0, maxLength), "...");

    private static List<SearchResult> SimulateSearchResults(string query)
    {
        // Deterministic simulated results based on query hash for demo purposes.
        var hash = Math.Abs(query.GetHashCode());
        var baseUrl = "https://example.com/article";

        return
        [
            new($"{baseUrl}/{hash % 1000}",
                $"Overview of {query}",
                $"A comprehensive overview covering the main aspects of {query}. "
                + "This source provides foundational context and key definitions relevant to the topic."),

            new($"{baseUrl}/{(hash + 1) % 1000}",
                $"Recent developments in {query}",
                $"Recent research and developments related to {query}. "
                + "Highlights emerging trends, new findings, and expert opinions from the past year."),

            new($"{baseUrl}/{(hash + 2) % 1000}",
                $"Analysis: {query}",
                $"In-depth analysis examining multiple perspectives on {query}. "
                + "Discusses implications, challenges, and future directions identified by domain experts."),
        ];
    }

    private sealed record SearchResult(string Url, string Title, string Snippet);
}

